import{c as t,Q as d,j as o,m as a}from"./chunks/framework.DVkeSyfh.js";const b=JSON.parse('{"title":"Web API Reference","description":"","frontmatter":{},"headers":[],"relativePath":"api.md","filePath":"api.md","lastUpdated":1780256562000}'),r={name:"api.md"};function c(s,e,i,n,l,p){return d(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="web-api-reference" tabindex="-1">Web API Reference <a class="header-anchor" href="#web-api-reference" aria-label="Permalink to &quot;Web API Reference&quot;">​</a></h1><p>This page documents the FastAPI endpoints used by the frontend. Most users do not need to call these endpoints directly; use this page when debugging the web UI, integrating a local script, or checking which backend action a UI button uses.</p><h2 id="web-api-reference-1" tabindex="-1">Web API Reference <a class="header-anchor" href="#web-api-reference-1" aria-label="Permalink to &quot;Web API Reference&quot;">​</a></h2><p>The frontend uses these endpoints through <code>frontend/src/api.ts</code>.</p><p>The API is local-first. Endpoints that scan, analyze, search, preview, export, reset, clear, or relocate work against the selected SQLite database and local filesystem paths. Audio-file writes happen only through the explicit MAEST genre tag endpoints.</p><h3 id="conventions" tabindex="-1">Conventions <a class="header-anchor" href="#conventions" aria-label="Permalink to &quot;Conventions&quot;">​</a></h3><p>These shared conventions apply across the API:</p><table tabindex="0"><thead><tr><th>Convention</th><th>Meaning</th></tr></thead><tbody><tr><td><code>400</code> <code>DatabaseNotSelected</code></td><td>A database-aware endpoint was called before a database was selected. Select one with <code>/api/database/switch</code> first.</td></tr><tr><td><code>409</code> <code>DatabaseBusy</code></td><td>A database switch was attempted while a job was <code>queued</code> or <code>running</code>. Wait for or cancel the job, then retry.</td></tr><tr><td><code>404</code></td><td>Unknown track, job, or media id.</td></tr><tr><td>Job <code>state</code></td><td>One of <code>queued</code>, <code>running</code>, <code>completed</code>, <code>cancelled</code>, or <code>failed</code>.</td></tr><tr><td><code>latest</code> job endpoints</td><td>Return <code>null</code> when no job of that family has run yet.</td></tr></tbody></table><p>Long-running work (scan, tag refresh, multi-model audio analysis, classifier scoring, genre tag jobs) is started by a <code>POST</code> that returns an initial job-status object. The frontend then polls the matching <code>jobs/latest</code> or <code>jobs/{job_id}</code> endpoint and can request cooperative cancellation.</p><h3 id="database" tabindex="-1">Database <a class="header-anchor" href="#database" aria-label="Permalink to &quot;Database&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Purpose</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/api/database/current</code></td><td>Return selected database state.</td></tr><tr><td><code>POST</code></td><td><code>/api/database/switch</code></td><td>Switch to a database path.</td></tr><tr><td><code>POST</code></td><td><code>/api/database/dialog</code></td><td>Open a local database chooser dialog.</td></tr><tr><td><code>POST</code></td><td><code>/api/database/clear</code></td><td>Clear local SQLite tracks, embeddings, and dependent classifier scores.</td></tr></tbody></table><p>Use these endpoints when selecting the active library database. <code>clear</code> is a database operation, not an audio-file delete operation, but it removes the library index and analysis rows from the selected SQLite file.</p><h3 id="library" tabindex="-1">Library <a class="header-anchor" href="#library" aria-label="Permalink to &quot;Library&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Purpose</th></tr></thead><tbody><tr><td><code>POST</code></td><td><code>/api/library/scan</code></td><td>Start a scan job for a root folder.</td></tr><tr><td><code>POST</code></td><td><code>/api/library/tags/refresh</code></td><td>Start a Mutagen tag refresh job.</td></tr><tr><td><code>POST</code></td><td><code>/api/library/relocate</code></td><td>Preview or apply stored path relocation.</td></tr><tr><td><code>GET</code></td><td><code>/api/library/summary</code></td><td>Return counters for tracks, analysis families, liked tracks, and complete promoted-classifier score coverage.</td></tr><tr><td><code>GET</code></td><td><code>/api/tracks</code></td><td>Return a paginated/searchable track page.</td></tr><tr><td><code>GET</code></td><td><code>/api/tracks/{track_id}</code></td><td>Return one full track payload.</td></tr><tr><td><code>POST</code></td><td><code>/api/tracks/{track_id}/liked</code></td><td>Save or remove the local liked flag for one track.</td></tr><tr><td><code>POST</code></td><td><code>/api/tracks/filtered</code></td><td>Return filtered track rows for selection workflows.</td></tr></tbody></table><p><code>/api/tracks</code> and <code>/api/tracks/filtered</code> accept <code>preset=syncopated</code> to filter on the stored MAEST syncopated-rhythm flag. They accept <code>liked=true</code> to show only liked tracks, and classifier threshold maps to filter tracks by stored classifier scores.</p><p>The <code>q</code> search parameter keeps substring <code>LIKE</code> behavior by default. Pass <code>search_mode=fts</code> to use the explicit token-based FTS5 index instead. FTS is token-based: it does not match arbitrary substrings inside a token. It is usually much faster for counting or narrowing token matches, but the paged track response still sorts results by library order, so first-page latency can vary for very common terms.</p><p>Use <code>/api/tracks</code> for paged browsing and <code>/api/tracks/{track_id}</code> only when a full metadata dialog needs one track. This keeps large libraries responsive.</p><p><code>/api/library/summary</code> includes a <code>classifiers</code> counter. It counts a track only when the track has stored <code>track_classifier_scores</code> rows for every promoted classifier discovered from <code>models/classifiers/*/model.json</code>.</p><p><code>/api/library/relocate</code> is a preview-first endpoint: it returns the relocation plan by default and only updates stored <code>tracks.path</code> values when <code>apply</code> is <code>true</code>. It has no button in the current web UI and no method in <code>frontend/src/api.ts</code>; drive relocation from the <code>dj-sim relocate-library</code> CLI command or a direct API call. Apply is rejected when there are conflicts or missing target files.</p><h3 id="jobs" tabindex="-1">Jobs <a class="header-anchor" href="#jobs" aria-label="Permalink to &quot;Jobs&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Purpose</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/api/library/scan/jobs/latest</code></td><td>Return latest scan or tag-refresh job.</td></tr><tr><td><code>GET</code></td><td><code>/api/library/scan/jobs/{job_id}</code></td><td>Return one scan job.</td></tr><tr><td><code>POST</code></td><td><code>/api/library/scan/jobs/{job_id}/cancel</code></td><td>Request scan cancellation.</td></tr><tr><td><code>GET</code></td><td><code>/api/analysis/jobs/latest</code></td><td>Return latest multi-model audio analysis job.</td></tr><tr><td><code>GET</code></td><td><code>/api/analysis/jobs/{job_id}</code></td><td>Return one multi-model audio analysis job.</td></tr><tr><td><code>POST</code></td><td><code>/api/analysis/jobs/{job_id}/cancel</code></td><td>Request multi-model analysis cancellation.</td></tr><tr><td><code>GET</code></td><td><code>/api/classifiers/{classifier_key}/analyze/jobs/latest</code></td><td>Return latest classifier job.</td></tr><tr><td><code>GET</code></td><td><code>/api/classifiers/{classifier_key}/analyze/jobs/{job_id}</code></td><td>Return one classifier job.</td></tr><tr><td><code>POST</code></td><td><code>/api/classifiers/{classifier_key}/analyze/jobs/{job_id}/cancel</code></td><td>Request classifier cancellation.</td></tr><tr><td><code>GET</code></td><td><code>/api/tags/genres/jobs/latest</code></td><td>Return latest genre tag write job.</td></tr><tr><td><code>GET</code></td><td><code>/api/tags/genres/jobs/{job_id}</code></td><td>Return one genre tag write job.</td></tr><tr><td><code>POST</code></td><td><code>/api/tags/genres/jobs/{job_id}/cancel</code></td><td>Request genre tag write cancellation.</td></tr></tbody></table><p>Job endpoints let the frontend poll long-running work and request cancellation. Cancellation is cooperative: a job may finish the current track or batch before it stops.</p><h3 id="analysis-and-search" tabindex="-1">Analysis and Search <a class="header-anchor" href="#analysis-and-search" aria-label="Permalink to &quot;Analysis and Search&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Purpose</th></tr></thead><tbody><tr><td><code>POST</code></td><td><code>/api/analysis/jobs</code></td><td>Start one selected-model audio-analysis job for SONARA, MAEST, MERT, and/or CLAP.</td></tr><tr><td><code>GET</code></td><td><code>/api/classifiers</code></td><td>List promoted classifiers from <code>models/classifiers/*/model.json</code>.</td></tr><tr><td><code>POST</code></td><td><code>/api/classifiers/{classifier_key}/analyze</code></td><td>Start classifier scoring.</td></tr><tr><td><code>POST</code></td><td><code>/api/classifiers/reset</code></td><td>Delete stored scores for the given classifier keys.</td></tr><tr><td><code>POST</code></td><td><code>/api/analysis/reset</code></td><td>Reset one analysis family.</td></tr><tr><td><code>POST</code></td><td><code>/api/search</code></td><td>Search in MERT embedding space.</td></tr><tr><td><code>POST</code></td><td><code>/api/search/sonara</code></td><td>Search with Sonara features.</td></tr><tr><td><code>POST</code></td><td><code>/api/search/text</code></td><td>Search CLAP audio vectors from text.</td></tr></tbody></table><p>Use <code>/api/analysis/jobs</code> before search endpoints when a library has not been processed yet. Its request body accepts <code>models</code>, <code>limit</code>, <code>device</code>, <code>top_k</code>, <code>track_batch_size</code>, <code>inference_batch_size</code>, and optional <code>classifier_keys</code>. <code>models</code> defaults to all four audio models (<code>sonara</code>, <code>maest</code>, <code>mert</code>, <code>clap</code>) and must be a non-empty subset. <code>limit: null</code> means all eligible tracks; positive limits count candidate tracks that are missing at least one selected model.</p><p><code>track_batch_size</code> controls how many decoded tracks the job holds and processes together. <code>inference_batch_size</code> controls MAEST/MERT/CLAP model forward-pass batches. The default values are <code>track_batch_size=4</code> and <code>inference_batch_size=24</code>. The former single <code>batch_size</code> request field is no longer accepted.</p><p>The analysis job skips selected-model results that already exist. Its top-level status uses <code>total</code>, <code>processed</code>, <code>analyzed</code>, <code>failed</code>, and <code>skipped</code> for track-level counters. <code>model_progress</code> keeps per-model counters for model-level writes and failures. Status responses expose <code>track_batch_size</code> and <code>inference_batch_size</code>; the legacy response field <code>batch_size</code> is not emitted. <code>classifier_keys</code> echoes any promoted classifier tail requested for the job. <code>current_model</code> identifies which selected model or classifier tail is currently running. Empty search results often mean the required Sonara features, MERT embeddings, or CLAP embeddings are missing for the candidate tracks.</p><p><code>GET /api/classifiers</code> needs no database; it discovers promoted profiles on disk. The UI can start promoted classifier scoring from the same analysis control block as the audio models by enabling <code>CLASSIFIERS</code>; the frontend sends the discovered profile keys as <code>/api/analysis/jobs</code> <code>classifier_keys</code>. The analysis job runs those classifiers after all selected audio models complete. If CLAP is selected, the classifier tail waits for CLAP even though classifier scoring itself only needs SONARA, MERT, and MAEST inputs. Tracks without those required inputs are skipped. The standalone <code>/api/classifiers/{classifier_key}/analyze</code> endpoint remains for classifier-only runs. <code>/api/classifiers/reset</code> accepts a list of classifier keys and deletes their <code>track_classifier_scores</code> rows (an empty list deletes nothing).</p><p>The default result limit for <code>/api/search</code>, <code>/api/search/sonara</code>, and <code>/api/search/text</code> is <code>10</code> when a request omits <code>limit</code>.</p><p><code>POST /api/search/text</code> accepts <code>query</code>, <code>limit</code>, optional <code>min_similarity</code>, and optional <code>device</code>. It also accepts adaptive contrast fields: <code>positive_queries</code>, <code>negative_queries</code>, <code>adaptive_contrast</code>, and <code>preset</code>. When <code>adaptive_contrast</code> is true and at least one <code>negative_queries</code> item is present, the endpoint embeds every positive and negative prompt and ranks CLAP audio vectors by <code>max positive similarity - max negative similarity</code>. Without a negative prompt it falls back to direct CLAP text-vector search for the first positive query.</p><p>Reset scope by family:</p><table tabindex="0"><thead><tr><th>Reset</th><th>Removes</th></tr></thead><tbody><tr><td><code>/api/analysis/reset</code> <code>sonara</code></td><td><code>sonara_*</code> metadata keys; recomputes stored BPM/key/energy/duration from remaining metadata.</td></tr><tr><td><code>/api/analysis/reset</code> <code>maest</code></td><td><code>maest_*</code> metadata keys plus <code>maest</code> embeddings.</td></tr><tr><td><code>/api/analysis/reset</code> <code>mert</code> / <code>clap</code></td><td>Embeddings of that key.</td></tr><tr><td><code>/api/classifiers/reset</code></td><td><code>track_classifier_scores</code> rows for the listed classifier keys.</td></tr></tbody></table><h3 id="export-tags-dialogs-media" tabindex="-1">Export, Tags, Dialogs, Media <a class="header-anchor" href="#export-tags-dialogs-media" aria-label="Permalink to &quot;Export, Tags, Dialogs, Media&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Purpose</th></tr></thead><tbody><tr><td><code>POST</code></td><td><code>/api/export</code></td><td>Export selected tracks as M3U or CSV.</td></tr><tr><td><code>POST</code></td><td><code>/api/tags/genres/apply</code></td><td>Write MAEST genres synchronously to every track that has MAEST genres.</td></tr><tr><td><code>POST</code></td><td><code>/api/tags/genres/jobs</code></td><td>Start a cancellable background MAEST genre tag write job.</td></tr><tr><td><code>POST</code></td><td><code>/api/dialog/folder</code></td><td>Open a folder chooser dialog.</td></tr><tr><td><code>GET</code></td><td><code>/media/{track_id}</code></td><td>Serve browser-playable audio for one track.</td></tr></tbody></table><p>Both genre tag endpoints apply to all tracks that have stored MAEST genres. They do not accept a track subset: a request body with <code>track_ids</code> is rejected with HTTP <code>400</code>. They are the explicit audio-file write path and overwrite only the standard genre field.</p><p>The frontend preview player uses <code>/media/{track_id}</code> and starts playback after a preview button click. AIFF/AIF responses are transcoded to temporary WAV files for browser compatibility and scrubbing support without rewriting source audio. If preview preparation fails, for example because FFmpeg rejects a malformed file, the endpoint returns HTTP <code>422</code> with the FFmpeg error text instead of raising an internal traceback.</p><p>Use <code>/api/export</code> for playlist/report files. Prefer <code>/api/tags/genres/jobs</code> for genre writes so progress and cancellation are available; the synchronous <code>/api/tags/genres/apply</code> returns one result row per track but blocks until the whole batch finishes.</p>',37)])])}const f=t(r,[["render",c]]);export{b as __pageData,f as default};
